ListNode* Solution::removeZeroSumSublists(ListNode* head) {
    ListNode dummy(0);
    dummy.next = head;
    int prefixSum = 0;
    unordered_map<int, ListNode*> prefixSumToNode;
    prefixSumToNode[0] = &dummy;
    while (head) {
        prefixSum += head->val;
        if (prefixSumToNode.find(prefixSum) != prefixSumToNode.end()) {
            ListNode* node = prefixSumToNode[prefixSum];
            ListNode* next = head->next;
            int newPrefixSum = prefixSum - (node->val - dummy.val);
            while (node != &dummy) {
                prefixSumToNode.erase(node->val);
                node = node->next;
            }
            node->next = next;
            node->val = newPrefixSum;
            prefixSumToNode[newPrefixSum] = node;
        } else {
            prefixSumToNode[prefixSum] = head;
        }
        head = head->next;
    }
    return dummy.next;
}
